// Import necessary dependencies
import okhttp3.OkHttpClient;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class ApiModule {
    // Base URLs for different environments
    private static final String DEVELOPMENT_URL = "https://api-dev.example.com";
    private static final String STAGING_URL = "https://api-staging.example.com";
    private static final String PRODUCTION_URL = "https://api.example.com";
    
    // Interface for defining the API endpoints
    public interface UserApi {
        @GET("users")
        Call<List<User>> getUsers();
    }
    
    // Method to create Retrofit service
    private static <S> S createService(Class<S> serviceClass, String baseUrl) {
        OkHttpClient.Builder httpClient = new OkHttpClient.Builder();
        
        Retrofit.Builder builder = new Retrofit.Builder()
                .baseUrl(baseUrl)
                .addConverterFactory(GsonConverterFactory.create());
                
        Retrofit retrofit = builder.client(httpClient.build()).build();
        
        return retrofit.create(serviceClass);
    }
    
    // Method to get the service with correct URL based on environment
    public static UserApi createUserService(Environment environment) {
        switch (environment) {
            case DEVELOPMENT:
                return ApiModule.createService(UserApi.class, DEVELOPMENT_URL);
            case STAGING:
                return ApiModule.createService(UserApi.class, STAGING_URL);
            case PRODUCTION:
                return ApiModule.createService(UserApi.class, PRODUCTION_URL);
            default:
                throw new IllegalArgumentException("Unknown environment");
        }
    }
    
    // Define the different environments as ENUM values
    public enum Environment {
        DEVELOPMENT, STAGING, PRODUCTION
    }
}